configuration.tbelScript:
function nextRelation(metadata, msg) {
    var out_list = [];
    switch (msg.method) {
        case "createScene":
        case "editScene":
            out_list = ['createScene']
            break;
            
        case "addDevToScene":
            out_list = ['addDevToScene']
            break;
            
        case "delDevFromScene":
            out_list = ['delDevFromScene']
            break;
            
        case "delScene":
            out_list = ['delScene']
            break;

        case "createSceneController":
            out_list = ['createSceneController']
            break;
            
        case "delSceneController":
            out_list = ['delSceneController']
            break;


        case "updateSceneName":
            out_list = ['updateSceneName']
            break;
    
        default:
            out_list = ['otherMethod']
            break;
    }
    return out_list;
}
return nextRelation(metadata, msg);

configuration.jsScript:
function splitSceneByGateway(input) {

    // Validate
    if (
        !input ||
        !input.params ||
        !input.params.devices ||
        !input.params.devices.length
    ) {
        return [];
    }

    var params = input.params;
    var devices = params.devices;

    // gatewayMap:
    // {
    //   gatewayName: {
    //       devices: []
    //   }
    // }
    var gatewayMap = {};

    var i;

    // =====================================================
    // STEP 1: Group devices theo gateway
    // =====================================================
    for (i = 0; i < devices.length; i++) {

        var device = devices[i];

        if (!device || !device.gateway) {
            continue;
        }

        var gateway = device.gateway;

        if (!gatewayMap[gateway]) {
            gatewayMap[gateway] = {
                devices: []
            };
        }

        gatewayMap[gateway].devices.push(device);
    }

    // =====================================================
    // STEP 2: Build output
    // =====================================================
    var result = [];

    for (var gatewayKey in gatewayMap) {

        if (!gatewayMap.hasOwnProperty(gatewayKey)) {
            continue;
        }

        var item = gatewayMap[gatewayKey];

        result.push({
            method: input.method,
            params: {
                id: params.id,
                dormitoryId: params.dormitoryId,
                room: params.room,
                gateway: gatewayKey,
                name: params.name,
                image: params.image,
                devices: item.devices
            }
        });
    }

    return result;
}

metadata.entityName = msg.params.id
metadata.entityName_Dormitory = msg.params.dormitoryId
metadata.entityName_Room = msg.params.room
metadata.lable = msg.params.name
msg = splitSceneByGateway(msg)
return { msg: msg, metadata: metadata, msgType: msgType };

